# Session Fixation Vulnerability
# Attacker sends victim a link with pre-set session ID
# https://example.com/login?session_id=attacker_known_value

# VULNERABLE - Session not regenerated after login
def login_vulnerable(username, password):
    if verify_credentials(username, password):
        session['user_id'] = user.id
        return redirect('/dashboard')
    # Session ID remains the same after authentication

# SECURE - Regenerate session after login
def login_secure(username, password):
    if verify_credentials(username, password):
        request.session.regenerate()  # New session ID
        session['user_id'] = user.id
        return redirect('/dashboard')
